const folderId = "<folder-id>";
const includeTimestamp = false;
if (!folderId || folderId.includes("<folder-id>")) {
  console.log("Set folderId to a Google Drive folder id before running this cell.");
} else {
  try {
    const nb = runme.getCurrentNotebook();
    if (!nb) {
      throw new Error("No active notebook handle available.");
    }
    const sourceName =
      (typeof nb.getName === "function" && nb.getName()) || "codex-walkthrough";
    const baseName = sourceName.replace(/\.(json|runme\.md|md)$/i, "");
    let fileName = `${baseName}-copy.json`;
    if (includeTimestamp) {
      const now = new Date();
      const pad = (n) => String(n).padStart(2, "0");
      const timestamp = `${now.getFullYear()}${pad(now.getMonth() + 1)}${pad(now.getDate())}-${pad(now.getHours())}${pad(now.getMinutes())}${pad(now.getSeconds())}`;
      fileName = `${baseName}-copy-${timestamp}.json`;
    }
    const result = await drive.saveAsCurrentNotebook(folderId, fileName);
    console.log(result);
    console.log("This tab is now pointing at the new Drive-backed copy.");
  } catch (err) {
    console.error("Failed to save notebook as a Google Drive copy", {
      error: String(err),
    });
    throw err;
  }
}

const runnerName = "local";
const runnerEndpoint = "ws://localhost:9977/ws";
const harnessName = "local-codex";
const harnessBaseUrl = window.location.origin;
const projectName = "Codex Walkthrough";
const projectCwd = ".";
const projectModel = "gpt-5";
const projectSandboxPolicy = "workspace-write";
const projectApprovalPolicy = "never";
const projectPersonality = "default";

if (!app?.runners || !app?.harness || !app?.codex?.project) {
  throw new Error(
    "Missing app.runners, app.harness, or app.codex.project in AppKernel globals.",
  );
}

const projectLines = String(app.codex.project.list() || "")
  .split("\n")
  .map((line) => line.trim())
  .filter(Boolean);

let projectId = null;
for (const line of projectLines) {
  const match = line.match(/^([^:]+):\s*(.+?)\s*\((.+?),/);
  if (!match) {
    continue;
  }
  const [, id, name, cwd] = match;
  if (name === projectName && cwd === projectCwd) {
    projectId = id;
    break;
  }
}

let projectCreateResult = "existing";
if (!projectId) {
  projectCreateResult = String(
    app.codex.project.create(
      projectName,
      projectCwd,
      projectModel,
      projectSandboxPolicy,
      projectApprovalPolicy,
      projectPersonality,
    ),
  );
  const match = projectCreateResult.match(/\(([^)]+)\)$/);
  projectId = match?.[1] ?? null;
}

if (!projectId) {
  throw new Error(`Could not resolve codex project id from: ${projectCreateResult}`);
}

const result = {
  runnerUpdate: app.runners.update(runnerName, runnerEndpoint),
  runnerDefault: app.runners.setDefault(runnerName),
  harnessUpdate: app.harness.update(harnessName, harnessBaseUrl, "codex"),
  harnessDefault: app.harness.setDefault(harnessName),
  activeChatkitUrl: app.harness.getActiveChatkitUrl(),
  projectCreateResult,
  projectDefault: app.codex.project.setDefault(projectId),
  projectState: app.codex.project.getDefault(),
};

console.log(result);
